tool.usage_example_filter:
        Find documents with specific property values

<use_mcp_tool>
<server_name>content-repository</server_name>
<tool_name>document_search</tool_name>
<arguments>
{
  "search_parameters": {
    "search_class": "HRDocument",
    "search_properties": [
      {
        "property_name": "Department",
        "property_value": "IT",
        "operator": "="
      }
    ]
  },
  "max_results": 50
}
</arguments>
</use_mcp_tool>
